import React, { useEffect, useState } from 'react';
import './StubPages.css';

const API_URL = 'http://localhost:5000/api';

const PatientsList = ({ onNavigate }) => {
  const [patients, setPatients] = useState([]);
  const [filteredPatients, setFilteredPatients] = useState([]);
  const [searchTerm, setSearchTerm] = useState('');
  const [loading, setLoading] = useState(true);
  const [error, setError] = useState('');

  useEffect(() => {
    fetchPatients();
  }, []);

  const fetchPatients = async () => {
    try {
      setLoading(true);
      setError('');

      const response = await fetch(`${API_URL}/patients`);
      const result = await response.json();

      if (result.success) {
        setPatients(result.data || []);
        setFilteredPatients(result.data || []);
      } else {
        setError(result.error || 'Failed to load patients');
      }
    } catch (err) {
      console.error('Error:', err);
      setError('Unable to connect to server');
    } finally {
      setLoading(false);
    }
  };

  const handleSearch = (e) => {
    const term = e.target.value.toLowerCase();
    setSearchTerm(term);

    const filtered = patients.filter(patient =>
      patient.firstName.toLowerCase().includes(term) ||
      patient.lastName.toLowerCase().includes(term) ||
      patient.email.toLowerCase().includes(term) ||
      patient.phone.includes(term)
    );

    setFilteredPatients(filtered);
  };

  const getStatusColor = (status) => {
    const colors = {
      'active': '#4caf50',
      'inactive': '#999',
    };
    return colors[status] || '#4a90e2';
  };

  if (loading) {
    return (
      <div className="page-wrapper">
        <div className="page-header">
          <h1>👥 Patients List</h1>
        </div>
        <div className="loading-state">
          <div className="spinner"></div>
          <p>Loading patients...</p>
        </div>
      </div>
    );
  }

  return (
    <div className="page-wrapper">
      <div className="page-header">
        <h1>👥 Patients List</h1>
        <p>All registered patients in the system</p>
      </div>

      {error && (
        <div className="error-message">
          <span>⚠️</span>
          <p>{error}</p>
          <button onClick={fetchPatients} className="retry-btn">Retry</button>
        </div>
      )}

      <div className="page-content">
        <div className="filter-bar">
          <input
            type="search"
            placeholder="Search by name, email, or phone..."
            className="search-input"
            value={searchTerm}
            onChange={handleSearch}
          />
          <button className="btn-add" onClick={() => onNavigate('patient-registration')}>
            + Add Patient
          </button>
        </div>

        {filteredPatients.length === 0 ? (
          <div className="empty-state">
            <p>❌ No patients found</p>
            {patients.length === 0 ? (
              <button className="btn-add" onClick={() => onNavigate('patient-registration')}>
                Register First Patient
              </button>
            ) : (
              <p>Try adjusting your search term</p>
            )}
          </div>
        ) : (
          <div className="table-wrapper">
            <table className="data-table">
              <thead>
                <tr>
                  <th>Name</th>
                  <th>Email</th>
                  <th>Phone</th>
                  <th>Blood Group</th>
                  <th>Date of Birth</th>
                  <th>Status</th>
                  <th>Registered</th>
                </tr>
              </thead>
              <tbody>
                {filteredPatients.map((patient) => (
                  <tr key={patient.id}>
                    <td>
                      <div className="patient-name-cell">
                        <div className="patient-avatar-small">
                          {patient.firstName.charAt(0)}
                        </div>
                        <span>{patient.firstName} {patient.lastName}</span>
                      </div>
                    </td>
                    <td>{patient.email}</td>
                    <td>{patient.phone}</td>
                    <td>
                      <span className="badge-blood-group">{patient.bloodGroup}</span>
                    </td>
                    <td>{new Date(patient.dateOfBirth).toLocaleDateString()}</td>
                    <td>
                      <span
                        className="status-badge"
                        style={{ backgroundColor: getStatusColor(patient.status) }}
                      >
                        {patient.status}
                      </span>
                    </td>
                    <td>{new Date(patient.registeredAt).toLocaleDateString()}</td>
                  </tr>
                ))}
              </tbody>
            </table>
          </div>
        )}

        <div className="stats-summary">
          <div className="summary-item">
            <span>Total Patients:</span>
            <strong>{patients.length}</strong>
          </div>
          <div className="summary-item">
            <span>Showing:</span>
            <strong>{filteredPatients.length}</strong>
          </div>
          <div className="summary-item">
            <span>Active:</span>
            <strong>{patients.filter(p => p.status === 'active').length}</strong>
          </div>
        </div>
      </div>
    </div>
  );
};

export default PatientsList;
